agent:
  command: pnpm codex exec
  max_turns: 20
  turn_timeout_ms: 3600000

sandbox:
  runtime: node24
  workspace_path: /vercel/sandbox
  snapshot_on_success: true
  snapshot_on_failure: true

workflow:
  handoff_status: Human Review
  fatal_error_classes:
    - missing_workflow_file
    - unsafe_credentials

hooks:
  before_run:
    - pnpm install
  after_run:
    - pnpm test
---
```

ここには「sandbox」「agent command」「hooks」「prompt」「handoff」「attempt 内の retry policy」が入る。

